import React from "react";

const projects = [
  {
    title: "Non-Electrical Solar Tracker",
    description:
      "A mechanically oriented solar tracking concept designed to improve energy capture without relying on a complex electrical control system. The project focuses on using simple, reliable movement principles to follow the sun through the day, reduce energy loss, and keep the overall design economical. It reflects a product-development mindset by balancing performance, simplicity, and easy maintenance. The idea is especially useful where low-cost deployment and rugged operation are more important than advanced electronics.",
  },
  {
    title: "BESS Integration with Solar",
    description:
      "A battery energy storage system integration project that combines solar generation with storage to improve stability, availability, and energy utilization. The main goal is to smooth fluctuating solar output, store excess power for later use, and support smarter power management. This project shows interest in modern energy systems, practical control strategies, and real-world renewable deployment. It also connects well with manufacturing and product development because scalable energy solutions need robust hardware, clean architecture, and dependable operation.",
  },
  {
    title: "Remote Operated Accelerator System",
    description:
      "A remote-operated accelerator concept built around safe control, responsive operation, and user-focused functionality. The project emphasizes the importance of reliable actuation, command handling, and system coordination in applications where precise input and remote accessibility are required. From an engineering perspective, it strengthens understanding of motion control, interface design, and real-world constraints. The overall approach is about building a practical system that can be operated efficiently while keeping safety and consistency in mind.",
  },
  {
    title: "Li-Fi Communication System",
    description:
      "A Li-Fi communication project that explores data transmission using light instead of traditional radio-frequency methods. The project highlights how optical communication can support secure, interference-resistant data transfer in specific environments. It combines conceptual electronics understanding with experimentation around modulation, reception, and signal conversion. This project is a good example of engineering curiosity, because it connects core electrical knowledge with emerging communication ideas and shows how alternative technologies can be prototyped and evaluated.",
  },
];

function Projects() {
  return (
    <div className="section-shell">
      <div className="section-heading">
        <p className="eyebrow">Projects</p>
        <h2>Engineering work with practical and product-focused thinking</h2>
      </div>

      <div className="project-grid">
        {projects.map((project) => (
          <article className="project-card" key={project.title}>
            <h3>{project.title}</h3>
            <p>{project.description}</p>
          </article>
        ))}
      </div>
    </div>
  );
}

export default Projects;
